import os
from flask import Flask, request, jsonify
from kafka import KafkaProducer

KAFKA_BOOTSTRAP_SERVERS = os.getenv("KAFKA_BOOTSTRAP_SERVERS", "localhost:9092")
KAFKA_CLIENT_ID = os.getenv("KAFKA_CLIENT_ID", "flexible-event-publisher")

producer = KafkaProducer(
    bootstrap_servers=[s.strip() for s in KAFKA_BOOTSTRAP_SERVERS.split(",") if s.strip()],
    client_id=KAFKA_CLIENT_ID,
    acks=1,
    linger_ms=5,
)

app = Flask(__name__)

@app.post("/publish")
def publish():
    topic = request.args.get("topic") or (request.json.get("topic") if request.is_json else None)
    message = request.args.get("message") or (request.json.get("message") if request.is_json else None)

    if not topic:
        return jsonify({"ok": False, "error": "missing topic"}), 400
    if message is None:
        return jsonify({"ok": False, "error": "missing message"}), 400

    data = message.encode("utf-8") if isinstance(message, str) else bytes(message)

    fut = producer.send(topic, data)
    md = fut.get(timeout=10)

    return jsonify({
        "ok": True,
        "topic": md.topic,
        "partition": md.partition,
        "offset": md.offset,
        "timestamp": md.timestamp,
    }), 200

@app.get("/healthz")
def healthz():
    return "ok", 200

if __name__ == "__main__":
    host = os.getenv("HOST", "0.0.0.0")
    port = int(os.getenv("PORT", "8080"))
    app.run(host=host, port=port)